SELECT s.first_name 
FROM students s
INNER JOIN interests i ON s.student_id = i.student_id
WHERE i.automotive > (
    SELECT AVG(automotive) FROM interests
);

SELECT course_id, COUNT(*) AS dislike_count
FROM disliked_courses
GROUP BY course_id;

SELECT COUNT(DISTINCT student_id) AS num_of_students
FROM interests
WHERE architecture > 0;

SELECT course_name, semester, course_feedback, grade_received
FROM liked_courses
WHERE student_id = 1;

SELECT MAX(architecture) AS max_architecture
FROM interests
WHERE automotive = (
    SELECT MAX(automotive) AS max_automotive
    FROM interests
);
